import{_ as e,o as n,c as o,ae as r}from"./chunks/framework.DTQlDYOH.js";const u=JSON.parse('{"title":"Reference: Shorthand and legacy keys","description":"","frontmatter":{},"headers":[],"relativePath":"reference/shorthand.md","filePath":"reference/shorthand.md"}'),a={name:"reference/shorthand.md"};function s(i,t,d,h,c,g){return n(),o("div",null,[...t[0]||(t[0]=[r('<h1 id="reference-shorthand-and-legacy-keys" tabindex="-1">Reference: Shorthand and legacy keys <a class="header-anchor" href="#reference-shorthand-and-legacy-keys" aria-label="Permalink to &quot;Reference: Shorthand and legacy keys&quot;">​</a></h1><p>The engine normalizes several shorthand forms and legacy keys so you can write less JSON. These are applied during <strong>expand-game-rules</strong> before the game runs.</p><h2 id="key-renames" tabindex="-1">Key renames <a class="header-anchor" href="#key-renames" aria-label="Permalink to &quot;Key renames&quot;">​</a></h2><table tabindex="0"><thead><tr><th>You write</th><th>Becomes</th></tr></thead><tbody><tr><td><strong>thatMatches</strong></td><td><strong>conditions</strong> (value used as the single element or array of conditions)</td></tr><tr><td><strong>entityType</strong></td><td><strong>type</strong> (on entities)</td></tr><tr><td><strong>moveType</strong></td><td><strong>type</strong> (on moves)</td></tr><tr><td><strong>endConditions</strong></td><td><strong>endIf</strong></td></tr></tbody></table><p>So you can use <strong>endConditions</strong> instead of <strong>endIf</strong>, and <strong>thatMatches</strong> instead of <strong>conditions</strong> when there’s only one condition or you pass an array.</p><h2 id="condition-shorthands" tabindex="-1">Condition shorthands <a class="header-anchor" href="#condition-shorthands" aria-label="Permalink to &quot;Condition shorthands&quot;">​</a></h2><p>When a <strong>condition</strong> value is a <strong>string</strong>, it is replaced as follows:</p><table tabindex="0"><thead><tr><th>String</th><th>Expands to</th></tr></thead><tbody><tr><td><strong>isCurrentPlayer</strong></td><td>Is condition with matcher player from ctxPath currentPlayer</td></tr><tr><td><strong>isEmpty</strong></td><td>Not condition wrapping a single Contains condition</td></tr></tbody></table><p>So you can write <strong>thatMatches</strong>: <code>&quot;isCurrentPlayer&quot;</code> or <code>&quot;isEmpty&quot;</code> instead of the full condition object.</p><h2 id="result-shorthand" tabindex="-1">Result shorthand <a class="header-anchor" href="#result-shorthand" aria-label="Permalink to &quot;Result shorthand&quot;">​</a></h2><table tabindex="0"><thead><tr><th>You write</th><th>Expands to</th></tr></thead><tbody><tr><td><strong>ownerOfFirstResultEntity</strong></td><td>contextPath into results, first match, first entity, attributes.player</td></tr></tbody></table><p>Used in <strong>endIf</strong> when the win comes from a <strong>HasLine</strong> (or similar) condition: the winner is the owner of the first entity in the first match. So you can set <strong>result</strong> winner to <code>&quot;ownerOfFirstResultEntity&quot;</code> instead of writing the long contextPath.</p><h2 id="single-condition-to-array" tabindex="-1">Single condition to array <a class="header-anchor" href="#single-condition-to-array" aria-label="Permalink to &quot;Single condition to array&quot;">​</a></h2><p>If you pass a single condition object where an array is expected (e.g. <strong>conditions</strong>), the engine wraps it in an array. So <strong>thatMatches</strong> with an array like <code>&quot;type&quot;: &quot;Space&quot;</code> and <code>&quot;isEmpty&quot;</code> is valid.</p><h2 id="default-condition-type-is" tabindex="-1">Default condition type: Is <a class="header-anchor" href="#default-condition-type-is" aria-label="Permalink to &quot;Default condition type: Is&quot;">​</a></h2><p>If an object in a <strong>conditions</strong> array has no <strong>conditionType</strong>, the engine sets <strong>conditionType</strong> to <strong>&quot;Is&quot;</strong> and uses the object as the <strong>matcher</strong>. So you can write a single object with <strong>type</strong>: <code>&quot;Space&quot;</code> instead of wrapping it in an Is condition with matcher.</p><h2 id="target-as-string" tabindex="-1">target as string <a class="header-anchor" href="#target-as-string" aria-label="Permalink to &quot;target as string&quot;">​</a></h2><p>If <strong>target</strong> is a string (e.g. <code>&quot;mainGrid&quot;</code>), it is expanded to an Is condition with matcher name equal to that string.</p><p>So you can write <strong>target</strong>: <code>&quot;mainGrid&quot;</code> in conditions that accept a target.</p>',19)])])}const y=e(a,[["render",s]]);export{u as __pageData,y as default};
